ValidationRule.errorConditionFormula:
AND(
    ISCHANGED(StageName),
    TEXT(StageName) = "Contract",
    OR(
        /* Falla si la antigüedad está vacía o es menor a 6 */
        ISBLANK(Antiguedad_Laboral_en_Meses__c),
        Antiguedad_Laboral_en_Meses__c < 6,

        /* Falla si la línea está vacía o es menor/igual a 0 */
        ISBLANK(Linea_de_Credito_Aprobada__c),
        Linea_de_Credito_Aprobada__c < Linea_de_credito_solicitada__c,

        /* Falla si el score está vacío o es menor a 5 */
        ISBLANK(Score_Crediticio_Butro__c),
        Score_Crediticio_Butro__c < 5,

        /* Falla SI FALTA AL MENOS UNO de los 4 documentos (exige que estén todos) */
        ISBLANK(Doc_Boleta_Pago__c),
        ISBLANK(Doc_Recibo_Honorarios__c),
        ISBLANK(Doc_PDT__c),
        ISBLANK(Doc_Reporte_Tributario__c)
    )
)
